static inline int vt_sizeof_VkFormatProperties2(VkFormatProperties2* val) {
    int bufferSize = 0;
    bufferSize += 4; // sType
    void* pNext = val->pNext;
    while (pNext) {
        bufferSize += 4;
        VkBaseOutStructure* sBase = pNext;
        void* oldPNext = sBase->pNext;
        sBase->pNext = NULL;

        switch (sBase->sType) {
            case VK_STRUCTURE_TYPE_FORMAT_PROPERTIES_3: {
                bufferSize += 4;
                bufferSize += vt_sizeof_VkFormatProperties3((VkFormatProperties3*)pNext);
                break;
            }
            default: {
                bufferSize += 4;
                break;
            }
        }

        sBase->pNext = oldPNext;
        pNext = sBase->pNext;
    }
    bufferSize += 4;
    bufferSize += vt_sizeof_VkFormatProperties(&val->formatProperties);
    return bufferSize;
}

static inline void vt_serialize_VkFormatProperties2(VkFormatProperties2* val, char* outputBuffer) {
    int bufferOffset = 0;
    *(VkStructureType*)(outputBuffer + bufferOffset) = val->sType;
    bufferOffset += 4;
    if (val->pNext) {
        void* pNext = val->pNext;
        while (pNext) {
            VkBaseOutStructure* sBase = pNext;
            *(int*)(outputBuffer + bufferOffset) = sBase->sType;
            bufferOffset += 4;
            void* oldPNext = sBase->pNext;
            sBase->pNext = NULL;

            switch (sBase->sType) {
                case VK_STRUCTURE_TYPE_FORMAT_PROPERTIES_3: {
                    int itemSize = vt_sizeof_VkFormatProperties3((VkFormatProperties3*)pNext);
                    *(int*)(outputBuffer + bufferOffset) = itemSize;
                    bufferOffset += 4;
                    vt_serialize_VkFormatProperties3((VkFormatProperties3*)pNext, outputBuffer + bufferOffset);
                    bufferOffset += itemSize;
                    break;
                }
                default: {
                    *(int*)(outputBuffer + bufferOffset) = 0;
                    bufferOffset += 4;
                    break;
                }
            }

            sBase->pNext = oldPNext;
            pNext = sBase->pNext;
        }
    }

    *(int*)(outputBuffer + bufferOffset) = -1;
    bufferOffset += 4;
    vt_serialize_VkFormatProperties(&val->formatProperties, outputBuffer + bufferOffset);
    bufferOffset += vt_sizeof_VkFormatProperties(&val->formatProperties);
}

